SourceCode.Declaration:
/// <summary>
/// This class is an extension of formdatasource LedgerJournalTransCustPaym form and LedgerJournalTrans dataSource.
/// </summary>
[ExtensionOf(formDataSourceStr(LedgerJournalTransCustPaym, LedgerJournalTrans))]
internal final class ETGLedgerJournalTransCustPaym_Extension
{
}

Method.Source:
/// <summary>
/// In this method, making invoicenumber field as non-editable.
/// </summary>
/// <returns>int</returns>
int active()
{
    boolean showTermoFields, isAdvPrepayment;
    int ret =  next active();
    if(SalesParameters::find().ETGEnableCylinderTracking)
    {
        LedgerJournalTable ledgerJournalTable   = LedgerJournalTable::find(element.JournalNum);
        LedgerJournalName ledgerJournalName     = LedgerJournalName::find(ledgerJournalTable.JournalName);

        if(ledgerJournalName.JournalName == SalesParameters::find().ETGJournalName)
        {
            this.object(fieldNum(LedgerJournalTrans, MarkedInvoice)).allowEdit(false);
        }
    }
    if(VendParameters::find().ETGEnableTermoNumberFeature == NoYes::Yes)
    {
        LedgerJournalTrans ledgerJournalTrans   = this.cursor();

        showTermoFields = true;
        if(ledgerJournalTrans.Prepayment == NoYes::Yes)
        {
            isAdvPrepayment = true;
        }
    }
    this.object(fieldNum(LedgerJournalTrans, ETGTERMONumber)).visible(showTermoFields);
    this.object(fieldNum(LedgerJournalTrans, ETGMotherTERMONumber)).visible(showTermoFields);
    this.object(fieldNum(LedgerJournalTrans, ETGCustVendInvoiceId)).visible(showTermoFields);
    this.object(fieldNum(LedgerJournalTrans, ETGTERMONumber)).allowEdit(showTermoFields && isAdvPrepayment);
    return ret;
}
